<?php
namespace App\Services;use App\Models\Employee;use Carbon\Carbon;use Carbon\CarbonPeriod;use Illuminate\Support\Facades\DB;
class LeaveDayCalculator{public function calculate(Employee$employee,string$start,string$end,string$portion='full'):float{$from=Carbon::parse($start);$to=Carbon::parse($end);if($from->isSameDay($to)&&$portion!=='full')return .5;$assignment=DB::table('shift_assignments as a')->join('shifts as s','s.id','=','a.shift_id')->where('a.employee_id',$employee->id)->whereDate('a.effective_from','<=',$from)->where(fn($q)=>$q->whereNull('a.effective_to')->orWhereDate('a.effective_to','>=',$to))->select('s.weekly_off_days')->latest('a.effective_from')->first();$off=json_decode($assignment?->weekly_off_days??'[5]',true)?:[5];$holidays=DB::table('holidays')->whereBetween('date',[$from,$to])->where(fn($q)=>$q->whereNull('company_id')->orWhere('company_id',$employee->company_id))->where(fn($q)=>$q->whereNull('branch_id')->orWhere('branch_id',$employee->branch_id))->pluck('date')->map(fn($d)=>Carbon::parse($d)->toDateString())->all();$days=0;foreach(CarbonPeriod::create($from,$to)as$date)if(!in_array($date->dayOfWeek,$off,true)&&!in_array($date->toDateString(),$holidays,true))$days++;return(float)$days;}}
